import React, { useState } from 'react';
import { Routes, Route, useNavigate } from 'react-router-dom';
import 'bootstrap/dist/css/bootstrap.min.css';
import './App.css';
import './index.css';

import HomePage from './components/HomePage';
import AnalysisModal from './components/AnalysisModal';
import ResultsPage from './components/ResultsPage';

function App() {
  const [showModal, setShowModal] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);
  const navigate = useNavigate();

  const handleFileSelect = (file) => {
    setSelectedFile(file);
    setShowModal(true);
  };

  // UPDATED: receive the 'data' from the AnalysisModal (from Python)
  const handleAnalysisComplete = (data) => {
    setShowModal(false);

    // 1. Create a local URL for the original image so we can display it in the Results Page
    let fileUrl = null;
    if (selectedFile) {
      fileUrl = URL.createObjectURL(selectedFile);
    }

    // 2. Navigate to results and carry BOTH the Python data AND the Original Image
    navigate('/results', { 
      state: { 
        analysisData: data, 
        originalImage: fileUrl 
      } 
    });
  };

  const handleModalClose = () => {
    setShowModal(false);
    setSelectedFile(null);
  };

  return (
    <div className="App">
      <Routes>
        <Route 
          path="/" 
          element={
            <HomePage onFileSelect={handleFileSelect} />
          } 
        />
        <Route 
          path="/results" 
          element={
            <ResultsPage />
          } 
        />
      </Routes>
      
      <AnalysisModal
        show={showModal}
        selectedFile={selectedFile} 
        onClose={handleModalClose}
        onAnalysisComplete={handleAnalysisComplete}
      />
    </div>
  );
}

export default App;