import React, { useState, useRef } from 'react';
import BokehBackground from './BokehBackground';

const HomePage = ({ onFileSelect }) => {
  const [isDragging, setIsDragging] = useState(false);
  const [selectedFile, setSelectedFile] = useState(null);
  const fileInputRef = useRef(null);

  const handleDragOver = (e) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setIsDragging(false);
    
    const files = e.dataTransfer.files;
    if (files.length > 0 && files[0].type.startsWith('image/')) {
      setSelectedFile(files[0]);
    }
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith('image/')) {
      setSelectedFile(file);
    }
  };

  const handleClick = () => {
    fileInputRef.current?.click();
  };

  const handleStartAnalysis = () => {
    if (selectedFile) {
      onFileSelect(selectedFile);
    }
  };

  const handleClearSelection = () => {
    setSelectedFile(null);
  };

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center">
      <BokehBackground />
      <div className="text-center">
        <h1>AquaEye</h1>
        <h2>A Standardized System for Microparticulate Matter</h2>
        
        {!selectedFile ? (
          <>
            <div 
              className={`dropzone ${isDragging ? 'is-dragging' : ''}`}
              onDragOver={handleDragOver}
              onDragLeave={handleDragLeave}
              onDrop={handleDrop}
              onClick={handleClick}
            >
              <div className="dropzone-text">
                {isDragging ? 'Drop your specimen image here' : 'Drag & Drop Specimen Image Here'}
              </div>
              <div className="dropzone-subtext">or click to select specimen</div>
            </div>
            
            <input
              type="file"
              ref={fileInputRef}
              onChange={handleFileChange}
              accept="image/*"
              style={{ display: 'none' }}
            />
            
            <button 
              className="btn btn-primary btn-lg mt-3"
              onClick={handleClick}
            >
              Select Specimen
            </button>
          </>
        ) : (
          <>
            <div className="mb-4">
              <div className="text-muted mb-2">File Selected</div>
              <div className="fw-semibold text-primary">Specimen: {selectedFile.name}</div>
            </div>
            
            <button 
              className="btn btn-primary btn-lg me-3"
              onClick={handleStartAnalysis}
            >
              Start Analysis
            </button>
            
            <button 
              className="btn btn-secondary btn-lg"
              onClick={handleClearSelection}
            >
              Clear Selection
            </button>
          </>
        )}
      </div>
    </div>
  );
};

export default HomePage;